export const studioDocs = {
  init:       { sig: 'void init()',                                                    doc: 'Called once after the window opens, before the first update(). Optional.\nUse for one-time setup: colorkey(), building the map, seeding state.\nAvoid the static bool workaround — this is the right place.', docNL: 'Wordt éénmalig aangeroepen nadat het venster is geopend, vóór de eerste update(). Optioneel.\nGebruik voor eenmalige setup: colorkey(), de map bouwen, beginstatus instellen.' },
  update:     { sig: 'void update()',                                                  doc: 'Called every frame. Move things, read input. Optional.', docNL: 'Wordt elk frame aangeroepen. Beweeg dingen, lees de input. Optioneel.' },
  draw:       { sig: 'void draw()',                                                    doc: 'Called every frame after update. Draw things.', docNL: 'Wordt elk frame aangeroepen, na update(). Teken dingen.' },
  btn:        { sig: 'bool btn(int player, int button)',                               doc: 'Returns true while the button is held.\nplayer: 0 (WASD+ZX) or 1 (Arrows+,.)\nWhen on-screen controls are enabled, player 0 also reads the floating stick and A/B touch buttons.', docNL: 'Geeft true zolang de knop ingedrukt is.\nplayer: 0 (WASD+ZX) of 1 (pijltjes+,.)\nAls de bediening op het scherm aanstaat, leest speler 0 ook de zwevende stick en de A/B-knoppen.' },
  btnp:       { sig: 'bool btnp(int player, int button)',                              doc: 'Returns true only on the frame the button was pressed (edge-triggered).\nUse this to fire sfx() on a press without retriggering every frame.', docNL: 'Geeft alleen true op het frame waarin de knop ingedrukt werd (edge-triggered).\nHandig om sfx() één keer af te spelen bij een druk, zonder elk frame opnieuw te triggeren.' },
  touch_count:    { sig: 'int touch_count()',                                          doc: 'Number of fingers currently down (0..10). On desktop, mouse LMB counts as one touch.', docNL: 'Aantal vingers dat nu het scherm raakt (0..10). Op desktop telt de linkermuisknop als één aanraking.' },
  touch_x:        { sig: 'int touch_x(int i)',                                         doc: 'X position of touch i in canvas coordinates. Returns -1 if i is out of range.\nOn desktop, mouse LMB shows up as a touch.', docNL: 'X-positie van aanraking i in canvas-coördinaten. Geeft -1 als i buiten bereik is.\nOp desktop telt de linkermuisknop als een aanraking.' },
  touch_y:        { sig: 'int touch_y(int i)',                                         doc: 'Y position of touch i in canvas coordinates. Returns -1 if i is out of range.\nOn desktop, mouse LMB shows up as a touch.', docNL: 'Y-positie van aanraking i in canvas-coördinaten. Geeft -1 als i buiten bereik is.\nOp desktop telt de linkermuisknop als een aanraking.' },
  tap:            { sig: 'bool tap(int x, int y, int w, int h)',                       doc: 'True if any finger is inside this rectangle (canvas-space).\nOn desktop, mouse clicks register as taps.', docNL: 'Geeft true zolang er een vinger in deze rechthoek zit (canvas-coördinaten).\nOp desktop tellen muisklikken als taps.' },
  touch_controls: { sig: 'void touch_controls(bool on)',                               doc: 'Show or hide the on-screen stick + A/B. Call from your cart to override the editor default.', docNL: 'Toon of verberg de stick op het scherm + A/B. Roep dit aan vanuit je cartridge om de standaard van de editor te overschrijven.' },
  stick_x:        { sig: 'float stick_x()',                                            doc: 'Analog stick X axis: -1.0 to 1.0. Returns 0.0 when no finger is on the stick.', docNL: 'Analoge stick, X-as: -1.0 tot 1.0. Geeft 0.0 als er geen vinger op de stick ligt.' },
  stick_y:        { sig: 'float stick_y()',                                            doc: 'Analog stick Y axis: -1.0 to 1.0. Negative is up.', docNL: 'Analoge stick, Y-as: -1.0 tot 1.0. Negatief is omhoog.' },
  mouse_x:        { sig: 'int mouse_x()',                                               doc: 'X position of the mouse pointer in canvas coordinates. Always known on desktop, even with no button down (unlike touch).', docNL: 'X-positie van de muisaanwijzer in canvas-coördinaten. Op desktop altijd bekend, ook zonder ingedrukte knop (anders dan touch).' },
  mouse_y:        { sig: 'int mouse_y()',                                               doc: 'Y position of the mouse pointer in canvas coordinates. Always known on desktop, even with no button down (unlike touch).', docNL: 'Y-positie van de muisaanwijzer in canvas-coördinaten. Op desktop altijd bekend, ook zonder ingedrukte knop (anders dan touch).' },
  mouse_down:     { sig: 'bool mouse_down(int button)',                                 doc: 'True while a mouse button is held. Pass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.', docNL: 'True zolang een muisknop ingedrukt is. Geef MOUSE_LEFT, MOUSE_RIGHT of MOUSE_MIDDLE mee.' },
  mouse_pressed:  { sig: 'bool mouse_pressed(int button)',                              doc: 'True only on the frame the mouse button is pressed. Use for clicks.\nPass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.', docNL: 'True alleen in het frame waarin de muisknop wordt ingedrukt. Gebruik dit voor klikken.\nGeef MOUSE_LEFT, MOUSE_RIGHT of MOUSE_MIDDLE mee.' },
  mouse_released: { sig: 'bool mouse_released(int button)',                             doc: 'True only on the frame the mouse button is released. Pass MOUSE_LEFT, MOUSE_RIGHT, or MOUSE_MIDDLE.', docNL: 'True alleen in het frame waarin de muisknop wordt losgelaten. Geef MOUSE_LEFT, MOUSE_RIGHT of MOUSE_MIDDLE mee.' },
  mouse_wheel:    { sig: 'float mouse_wheel()',                                         doc: 'Scroll wheel movement this frame: positive up, negative down, 0 if no scroll.', docNL: 'Scrollwiel-beweging dit frame: positief omhoog, negatief omlaag, 0 zonder scrollen.' },
  mouse_world_x:  { sig: 'int mouse_world_x()',                                         doc: 'Mouse X in world space — undoes the active camera() shift. Use to click on a scrolled world instead of writing mouse_x() + cam_x yourself.\nReads the CURRENT camera, so if you read it in update() call camera() in update() too (not just draw()).\nint wx = mouse_world_x();', docNL: 'Muis-X in wereldcoördinaten — maakt de actieve camera()-verschuiving ongedaan. Gebruik dit om in een gescrollde wereld te klikken, in plaats van zelf mouse_x() + cam_x te schrijven.\nLeest de HUIDIGE camera, dus als je het in update() leest, roep camera() ook in update() aan (niet alleen in draw()).\nint wx = mouse_world_x();' },
  mouse_world_y:  { sig: 'int mouse_world_y()',                                         doc: 'Mouse Y in world space — undoes the active camera() shift. Reads the current camera (see mouse_world_x).\nint wy = mouse_world_y();', docNL: 'Muis-Y in wereldcoördinaten — maakt de actieve camera()-verschuiving ongedaan. Leest de huidige camera (zie mouse_world_x).\nint wy = mouse_world_y();' },
  MOUSE_LEFT:     { sig: '#define MOUSE_LEFT 0',                                        doc: 'Left mouse button — pass to mouse_down / mouse_pressed / mouse_released.', docNL: 'Linkermuisknop — geef mee aan mouse_down / mouse_pressed / mouse_released.' },
  MOUSE_RIGHT:    { sig: '#define MOUSE_RIGHT 1',                                       doc: 'Right mouse button — pass to mouse_down / mouse_pressed / mouse_released.', docNL: 'Rechtermuisknop — geef mee aan mouse_down / mouse_pressed / mouse_released.' },
  MOUSE_MIDDLE:   { sig: '#define MOUSE_MIDDLE 2',                                      doc: 'Middle mouse button — pass to mouse_down / mouse_pressed / mouse_released.', docNL: 'Middelste muisknop — geef mee aan mouse_down / mouse_pressed / mouse_released.' },
  key:            { sig: 'bool key(int k)',                                             doc: "True while a key is held. For letters/digits pass the character: key('A'), key('5'). For special keys use KEY_SPACE, KEY_LEFT, etc.", docNL: "True zolang een toets ingedrukt is. Voor letters/cijfers geef je het teken mee: key('A'), key('5'). Voor speciale toetsen gebruik KEY_SPACE, KEY_LEFT, enz." },
  keyp:           { sig: 'bool keyp(int k)',                                            doc: "True only on the frame the key was pressed (edge-triggered). key('A') or KEY_ENTER.", docNL: "True alleen in het frame waarin de toets werd ingedrukt (edge-triggered). key('A') of KEY_ENTER." },
  text_input:     { sig: 'const char *text_input()',                                   doc: 'The characters typed this frame, as a string (empty if none). For name entry, chat, word games.\nstrcat your buffer with it; handle KEY_BACKSPACE yourself.', docNL: 'De tekens die dit frame getypt zijn, als string (leeg als er niets is). Voor het invoeren van namen, chat, woordspellen.\nPlak het aan je buffer; KEY_BACKSPACE handel je zelf af.' },
  KEY_SPACE:      { sig: '#define KEY_SPACE 32',     doc: 'Spacebar — pass to key() / keyp().', docNL: 'Spatiebalk — geef mee aan key() / keyp().' },
  KEY_ENTER:      { sig: '#define KEY_ENTER 257',    doc: 'Enter / Return — pass to key() / keyp().', docNL: 'Enter / Return — geef mee aan key() / keyp().' },
  KEY_BACKSPACE:  { sig: '#define KEY_BACKSPACE 259',doc: 'Backspace — pass to key() / keyp(). Use to delete a character during text entry.', docNL: 'Backspace — geef mee aan key() / keyp(). Gebruik om een teken te wissen bij tekstinvoer.' },
  KEY_ESCAPE:     { sig: '#define KEY_ESCAPE 256',   doc: 'Escape — pass to key() / keyp().', docNL: 'Escape — geef mee aan key() / keyp().' },
  KEY_TAB:        { sig: '#define KEY_TAB 258',      doc: 'Tab — pass to key() / keyp().', docNL: 'Tab — geef mee aan key() / keyp().' },
  KEY_LEFT:       { sig: '#define KEY_LEFT 263',     doc: 'Left arrow — pass to key() / keyp().', docNL: 'Pijl naar links — geef mee aan key() / keyp().' },
  KEY_RIGHT:      { sig: '#define KEY_RIGHT 262',    doc: 'Right arrow — pass to key() / keyp().', docNL: 'Pijl naar rechts — geef mee aan key() / keyp().' },
  KEY_UP:         { sig: '#define KEY_UP 265',       doc: 'Up arrow — pass to key() / keyp().', docNL: 'Pijl omhoog — geef mee aan key() / keyp().' },
  KEY_DOWN:       { sig: '#define KEY_DOWN 264',     doc: 'Down arrow — pass to key() / keyp().', docNL: 'Pijl omlaag — geef mee aan key() / keyp().' },
  print_scaled:   { sig: 'int print_scaled(const char *text, int x, int y, int color, int scale)', doc: 'Draw text bigger for titles and menus using the active font. scale 2 = double size, 3 = triple. Returns x after the last char.\nprint_scaled("GAME OVER", 60, 80, CLR_RED, 2);', docNL: 'Teken tekst groter voor titels en menu\'s met het actieve lettertype. scale 2 = dubbel, 3 = drie keer zo groot. Geeft x na het laatste teken terug.\nprint_scaled("GAME OVER", 60, 80, CLR_RED, 2);' },
  text_width:     { sig: 'int text_width(const char *text)',                            doc: 'Pixel width of text using the active font (set with font()). Use it to center text inside your own box:\nprint(s, bx + (bw - text_width(s))/2, y, c);', docNL: 'Pixelbreedte van tekst met het actieve lettertype (ingesteld via font()). Gebruik dit om tekst in je eigen vak te centreren:\nprint(s, bx + (bw - text_width(s))/2, y, c);' },
  font:           { sig: 'void font(int f)',                                            doc: 'Set the active font for all print calls. font(FONT_NORMAL) resets to the default 8×8.\nfont(FONT_SMALL); print("tiny hud", 4, 4, CLR_WHITE); font(FONT_NORMAL);', docNL: 'Stel het actieve lettertype in voor alle print-aanroepen. font(FONT_NORMAL) zet terug naar het standaard 8×8.\nfont(FONT_SMALL); print("tiny hud", 4, 4, CLR_WHITE); font(FONT_NORMAL);' },
  FONT_NORMAL:    { sig: '#define FONT_NORMAL 0',                                       doc: 'Default 8×8 DOS font — pass to font() to reset.\nfont(FONT_NORMAL);', docNL: 'Standaard 8×8 DOS-lettertype — geef mee aan font() om te resetten.\nfont(FONT_NORMAL);' },
  FONT_SMALL:     { sig: '#define FONT_SMALL 1',                                        doc: 'Compact 4×6 font — fits ~64 chars across 320px. Good for HUD lines and stat tables.\nfont(FONT_SMALL);', docNL: 'Compact 4×6-lettertype — past ~64 tekens op 320px. Fijn voor HUD-regels en statistiektabellen.\nfont(FONT_SMALL);' },
  FONT_TINY:      { sig: '#define FONT_TINY 2',                                         doc: 'Tiny 3×5 font — fits ~80 chars across 320px. Maximum info density.\nfont(FONT_TINY);', docNL: 'Mini 3×5-lettertype — past ~80 tekens op 320px. Maximale informatiedichtheid.\nfont(FONT_TINY);' },
  print_shadow:   { sig: 'int print_shadow(const char *text, int x, int y, int color, int shadow_color)', doc: 'Draw text with a drop shadow at (+1,+1). Much more legible over busy backgrounds. Returns x after the last char.\nprint_shadow("score", 4, 4, CLR_WHITE, CLR_BLACK);', docNL: 'Teken tekst met een slagschaduw op (+1,+1). Veel leesbaarder op drukke achtergronden. Geeft x na het laatste teken terug.\nprint_shadow("score", 4, 4, CLR_WHITE, CLR_BLACK);' },
  print_outline:  { sig: 'int print_outline(const char *text, int x, int y, int color, int outline_color)', doc: 'Draw text with a 1px outline in all 8 directions. Maximum legibility on any background. Returns x after the last char.\nprint_outline("LEVEL 1", 60, 90, CLR_YELLOW, CLR_BLACK);', docNL: 'Teken tekst met een 1px-omtrek in alle 8 richtingen. Maximale leesbaarheid op elke achtergrond. Geeft x na het laatste teken terug.\nprint_outline("LEVEL 1", 60, 90, CLR_YELLOW, CLR_BLACK);' },
  oval:           { sig: 'void oval(int x, int y, int rx, int ry, int color)',          doc: 'Ellipse border centered at (x,y). rx/ry are the half-width and half-height.', docNL: 'Ellips-omtrek met middelpunt (x,y). rx/ry zijn de halve breedte en halve hoogte.' },
  ovalfill:       { sig: 'void ovalfill(int x, int y, int rx, int ry, int color)',      doc: 'Filled ellipse centered at (x,y). Great for squashed circles, eyes, shadows.', docNL: 'Gevulde ellips met middelpunt (x,y). Fijn voor platgedrukte cirkels, ogen, schaduwen.' },
  arc:            { sig: 'void arc(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: "Draw part of a circle's rim, from start_deg to end_deg (degrees, 0=right, 90=down — same as dx/dy).\narc(80, 80, 20, 0, 90, 7);", docNL: "Teken een deel van de rand van een cirkel, van start_deg tot end_deg (graden, 0=rechts, 90=omlaag — net als dx/dy).\narc(80, 80, 20, 0, 90, 7);" },
  arcfill:        { sig: 'void arcfill(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: 'Filled pie wedge (a sector) from start_deg to end_deg. For cooldown sweeps, pie slices, a half-circle (0..180).\narcfill(80, 80, 20, -90, 0, 8);', docNL: 'Gevulde taartpunt (een sector) van start_deg tot end_deg. Voor cooldown-vegen, taartpunten, een halve cirkel (0..180).\narcfill(80, 80, 20, -90, 0, 8);' },
  arcoutline:     { sig: 'void arcoutline(int x, int y, int radius, float start_deg, float end_deg, int color)', doc: 'Outline of a filled pie wedge — the rim plus the two straight radial edges. Hugs arcfill() exactly (use arc() for just the curved rim).\narcoutline(80, 80, 20, -90, 0, 8);', docNL: 'Omtrek van een gevulde taartpunt — de rand plus de twee rechte zijden. Sluit precies om arcfill() (gebruik arc() voor alleen de gebogen rand).\narcoutline(80, 80, 20, -90, 0, 8);' },
  ring:           { sig: 'void ring(int x, int y, int r_in, int r_out, float start_deg, float end_deg, int color)', doc: 'Filled thick arc — the band between r_in and r_out, from start_deg to end_deg. For gauges, radial bars, dials.\nring(80, 80, 14, 20, 0, 270, 11);', docNL: 'Gevulde dikke boog — de band tussen r_in en r_out, van start_deg tot end_deg. Voor meters, ronde balken, draaiknoppen.\nring(80, 80, 14, 20, 0, 270, 11);' },
  ringoutline:    { sig: 'void ringoutline(int x, int y, int r_in, int r_out, float start_deg, float end_deg, int color)', doc: 'Outline of a ring/annulus sector — both rims and (for a partial sweep) the two radial edges. Hugs ring() exactly.\nringoutline(80, 80, 14, 20, 0, 270, 11);', docNL: 'Omtrek van een ring/annulus-sector — beide randen en (bij een deel-sweep) de twee rechte zijden. Sluit precies om ring().\nringoutline(80, 80, 14, 20, 0, 270, 11);' },
  pal:            { sig: 'void pal(int c0, int c1)',                                    doc: 'Remap a palette color: everything drawn as c0 now draws as c1 — shapes AND sprites. ⚠ STICKY: persists across every later draw AND into the next frame until pal_reset() — forget it and the swap leaks onto everything you draw after.\nDraw "magic" placeholder colors in a sprite, then pal() them per-entity for clothes/team recolors. Also hit-flash, fades.\npal(28, my_shirt); spr(0, x, y); pal_reset();', docNL: 'Wissel een paletkleur om: alles dat als c0 getekend wordt, wordt nu als c1 getekend — vormen ÉN sprites. ⚠ BLIJFT HANGEN: geldt voor al het latere tekenwerk ÉN het volgende frame tot pal_reset() — vergeet je het, dan lekt de omwisseling over alles wat je daarna tekent.\nTeken "magische" plaatshouder-kleuren in een sprite en wissel ze per-figuur om voor kleding-/teamkleuren. Ook hit-flash, fades.\npal(28, my_shirt); spr(0, x, y); pal_reset();' },
  pal_reset:      { sig: 'void pal_reset()',                                            doc: 'Undo every pal() swap — back to the normal 32 colors.', docNL: 'Maak alle pal()-wissels ongedaan — terug naar de normale 32 kleuren.' },
  fade:           { sig: 'void fade(float amount)',                                     doc: 'Darken the whole screen toward black for ONE frame. 0 = normal, 1 = fully black. For fade-in/out transitions between rooms or scenes.\nImmediate-mode: it clears automatically next frame, so call it every frame you want the screen dimmed (e.g. inside a game-over overlay). No need to reset it by hand.\nif (gameover) fade(0.5f);', docNL: 'Maak het hele scherm één frame lang donkerder richting zwart. 0 = normaal, 1 = helemaal zwart. Voor fade-overgangen tussen kamers of scenes.\nImmediate-mode: het wist zichzelf het volgende frame, dus roep het elk frame aan dat je het scherm donker wilt (bv. in een game-over overlay). Je hoeft het niet zelf te resetten.\nif (gameover) fade(0.5f);' },
  shake:          { sig: 'void shake(float amount)',                                    doc: 'Kick the screen by `amount` pixels. Call it on impacts, explosions, landings — instant game feel.\n✓ ENGINE-CLEARED: decays on its own over a few frames (like clip, you never reset it) — so you just call it once on the hit.', docNL: 'Schud het scherm met `amount` pixels. Roep aan bij klappen, explosies, landingen — directe game-feel.\n✓ DOOR DE ENGINE GEWIST: dooft vanzelf uit over een paar frames (net als clip zet je het nooit terug) — roep het dus één keer aan bij de klap.' },
  dt:             { sig: 'float dt()',                                                  doc: 'Seconds since the last frame (already clamped for hitches). Multiply movement and decay by it so speed is the same on any framerate:\nx += 60 * dt();  // 60 px per second', docNL: 'Seconden sinds het vorige frame (al begrensd tegen haperingen). Vermenigvuldig beweging en afname ermee zodat de snelheid op elke framerate gelijk is:\nx += 60 * dt();  // 60 px per seconde' },
  save_bytes:     { sig: 'void save_bytes(const void *data, int len)',                  doc: 'Save a whole block of bytes (a struct or array) that survives between runs — for state too big for the 64 int slots.\nsave_bytes(&world, sizeof world);', docNL: 'Sla een heel blok bytes op (een struct of array) dat runs overleeft — voor data die te groot is voor de 64 int-slots.\nsave_bytes(&world, sizeof world);' },
  load_bytes:     { sig: 'int load_bytes(void *out, int max)',                          doc: 'Read bytes saved with save_bytes() into `out` (up to max). Returns how many bytes were read (0 if never saved).\nload_bytes(&world, sizeof world);', docNL: 'Lees bytes die met save_bytes() zijn opgeslagen in `out` (maximaal max). Geeft het aantal gelezen bytes terug (0 als er nooit opgeslagen is).\nload_bytes(&world, sizeof world);' },
  cls:        { sig: 'void cls(int color)',                                            doc: 'Clear the screen to a palette color index (0–31).', docNL: 'Wis het scherm naar één paletkleur (index 0–31).' },
  colorkey:   { sig: 'void colorkey(int color)',                                       doc: 'Choose which palette color is treated as transparent when drawing sprites.\nAny pixel matching this color is skipped — so the background shows through.\nPass -1 to turn transparency off. Call once when the color changes, not every frame.', docNL: 'Kies welke paletkleur doorzichtig is bij het tekenen van sprites.\nPixels met deze kleur worden overgeslagen, zodat de achtergrond doorschijnt.\nGeef -1 om transparantie uit te zetten. Roep dit aan als de kleur verandert, niet elk frame.' },
  spr:        { sig: 'void spr(int index, int x, int y)',                             doc: 'Draw a sprite by its index at position (x, y).', docNL: 'Teken de sprite met dit indexnummer op positie (x, y).' },
  sprf:       { sig: 'void sprf(int index, int x, int y, bool flip_x, bool flip_y)',  doc: 'Like spr() but can be flipped horizontally and/or vertically.\nUseful for left/right facing characters.', docNL: 'Net als spr(), maar kan horizontaal en/of verticaal gespiegeld worden.\nHandig voor personages die naar links of rechts kijken.' },
  fillp:        { sig: 'void fillp(int pattern, int hole_color)',  doc: "PICO-8-style global fill pattern. Once set, the normal fills — rectfill, circfill, ovalfill, trifill — draw the 4×4 pattern: the draw color fills the 0-bits, the 1-bits use hole_color (pass -1 to make them transparent so the background shows through). ⚠ STICKY (you own this): stays on for every later fill AND into the next frame until fillp_reset() — forget it and unrelated shapes come out dithered.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); rectfill(0,0,320,200, CLR_BLUE); fillp_reset();", docNL: "PICO-8-achtig globaal vulpatroon. Eenmaal gezet tekenen de gewone vullingen — rectfill, circfill, ovalfill, trifill — het 4×4-patroon: de tekenkleur vult de 0-bits, de 1-bits krijgen hole_color (geef -1 om ze doorzichtig te maken). ⚠ BLIJFT HANGEN (jij beheert dit): blijft aan voor elke latere vulling ÉN het volgende frame tot fillp_reset() — vergeet je het, dan komen ongerelateerde vormen geditherd uit.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); rectfill(0,0,320,200, CLR_BLUE); fillp_reset();" },
  fillp_reset:  { sig: 'void fillp_reset()', doc: 'Turn off the global fill pattern set by fillp() — fills go back to solid.', docNL: 'Schakel het globale vulpatroon van fillp() uit — vullingen worden weer effen.' },
  fillp_anchor: { sig: 'void fillp_anchor(int ox, int oy)', doc: "Move the fill-pattern lattice origin to (ox,oy). By default the 4×4 pattern is pinned to world (0,0), so a MOVING shape slides over a fixed grid and the dither appears to crawl. Anchor to a shape's own center right before filling it and the pattern travels with the shape. fillp_anchor(0,0) restores the default.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); fillp_anchor(x, y); circfill(x, y, 8, CLR_BLUE); fillp_anchor(0,0);", docNL: "Verplaats de oorsprong van het vulpatroon-raster naar (ox,oy). Standaard is het 4×4-patroon vastgepind op wereld (0,0), dus een BEWEGENDE vorm schuift over een vast raster en de dither lijkt te kruipen. Anker op het middelpunt van een vorm vlak voordat je hem vult, dan reist het patroon mee met de vorm. fillp_anchor(0,0) herstelt de standaard.\nfillp(FILL_CHECKER, CLR_DARK_BLUE); fillp_anchor(x, y); circfill(x, y, 8, CLR_BLUE); fillp_anchor(0,0);" },
  FILL_SOLID:   { sig: '#define FILL_SOLID 0xFFFF',   doc: 'Pattern: fully solid (all bits set). Pass to fillp().', docNL: 'Patroon: volledig gevuld (alle bits aan). Geef mee aan fillp().' },
  FILL_CHECKER: { sig: '#define FILL_CHECKER 0xA5A5', doc: 'Pattern: 50% checkerboard.', docNL: 'Patroon: 50% dambord.' },
  FILL_DOTS:    { sig: '#define FILL_DOTS 0x8020',    doc: 'Pattern: sparse dots.', docNL: 'Patroon: spaarzame stippen.' },
  FILL_HLINES:  { sig: '#define FILL_HLINES 0xF0F0',  doc: 'Pattern: horizontal stripes.', docNL: 'Patroon: horizontale strepen.' },
  FILL_VLINES:  { sig: '#define FILL_VLINES 0xAAAA',  doc: 'Pattern: vertical stripes.', docNL: 'Patroon: verticale strepen.' },
  FILL_DIAG:    { sig: '#define FILL_DIAG 0x8421',    doc: 'Pattern: diagonal lines.', docNL: 'Patroon: diagonale lijnen.' },
  FILL_GRID:    { sig: '#define FILL_GRID 0xF888',    doc: 'Pattern: grid / brick lines.', docNL: 'Patroon: raster / bakstenen.' },
  spr_rot:    { sig: 'void spr_rot(int index, int x, int y, float deg)',              doc: 'Draw a sprite spun `deg` degrees around its own center. (x,y) is the top-left, same as spr().\nThe everyday rotate — a turning ship, a spinning pickup. For vanilla sprites just use spr().', docNL: 'Teken een sprite `deg` graden gedraaid rond zijn eigen midden. (x,y) is linksboven, net als spr().\nDe alledaagse rotatie — een draaiend schip, een tollende bonus. Voor gewone sprites gebruik je spr().' },
  sspr_ex:    { sig: 'void sspr_ex(int sx, int sy, int sw, int sh, int dx, int dy, int dw, int dh, float deg, int ox, int oy)', doc: 'The works: copy a source sub-rect (sx,sy,sw,sh) of the sheet to a dest rect (dx,dy,dw,dh) — so it scales — rotated `deg` degrees around the pivot (ox,oy), measured inside the dest from its top-left. Flip by passing a negative sw or sh.\nRotate around the dest center with ox=dw/2, oy=dh/2.', docNL: 'Alles-in-één: kopieer een bron-deelrechthoek (sx,sy,sw,sh) van het vel naar een doelrechthoek (dx,dy,dw,dh) — dus schaalt — `deg` graden gedraaid rond het draaipunt (ox,oy), gemeten binnen het doel vanaf linksboven. Spiegel met een negatieve sw of sh.\nDraai om het midden met ox=dw/2, oy=dh/2.' },
  sspr:       { sig: 'void sspr(int sx, int sy, int sw, int sh, int dx, int dy, int dw, int dh)', doc: 'Stretched sprite. Copies a sub-rectangle of the sprite sheet (sx,sy,sw,sh) to a destination rectangle (dx,dy,dw,dh).\nNon-equal sizes scale the result.', docNL: 'Uitgerekte sprite. Kopieert een stuk van de spritesheet (sx,sy,sw,sh) naar een doelvak (dx,dy,dw,dh).\nVerschillen in grootte rekken het resultaat uit.' },
  pget:       { sig: 'int pget(int x, int y)',                                        doc: "Read the palette index at (x, y). Reads from the previous frame's canvas.\nReturns 0 if the pixel does not match any palette color or is outside the screen.", docNL: 'Lees de paletindex op (x, y). Kijkt naar het canvas van het vorige frame.\nGeeft 0 als de pixel bij geen enkele paletkleur past of buiten het scherm ligt.' },
  camera:     { sig: 'void camera(int x, int y)',                                     doc: 'Plain camera: shifts all subsequent drawing by (-x, -y), with no zoom or rotation. Lets you scroll the world without per-call math.\n⚠ STICKY (you own this): the shift persists across frames until you change it — camera(0, 0) resets it, use that to switch back to screen space for a HUD.', docNL: 'Gewone camera: verschuift al het volgende tekenwerk met (-x, -y), zonder zoom of rotatie. Zo scroll je de wereld zonder bij elke aanroep zelf te rekenen.\n⚠ BLIJFT HANGEN (jij beheert dit): de verschuiving blijft over frames heen tot je het verandert — camera(0, 0) zet het terug; gebruik dit om terug te schakelen naar schermcoördinaten voor een HUD.' },
  camera_ex:  { sig: 'void camera_ex(int x, int y, float zoom, float angle)',         doc: 'Camera with zoom and rotation, pivoting on the screen center. zoom 1.0 = normal, 2.0 = 2x in, 0.5 = out; angle in degrees.\nFeed your scroll x/y each frame; for a screen-space HUD after zooming, call camera(0, 0).\n⚠ STICKY (you own this): persists across frames until you change it. If you read mouse_world_*() in update(), set the camera in update() too — not just draw().\ncamera_ex(camx, camy, 2.0f, 0);', docNL: 'Camera met zoom en rotatie, draaiend om het schermmidden. zoom 1.0 = normaal, 2.0 = 2x in, 0.5 = uit; hoek in graden.\nGeef elke frame je scroll x/y mee; voor een HUD in schermcoördinaten na het zoomen, roep camera(0, 0) aan.\n⚠ BLIJFT HANGEN (jij beheert dit): blijft over frames heen tot je het verandert. Lees je mouse_world_*() in update(), zet de camera dan ook in update() — niet alleen in draw().\ncamera_ex(camx, camy, 2.0f, 0);' },
  follow:     { sig: 'void follow(int tx, int ty, int world_w, int world_h)', doc: 'Center the camera on (tx, ty), clamped so world edges never show.\nworld_w and world_h are the total world size in pixels.\nTypically called at the end of update() with the player position.', docNL: 'Centreer de camera op (tx, ty), begrensd zodat de wereld­randen niet zichtbaar worden.\nworld_w en world_h zijn de totale wereld­grootte in pixels.\nGebruikelijk aan het einde van update() aangeroepen met de spelerpositie.' },
  clip:       { sig: 'void clip(int x, int y, int w, int h)',                         doc: 'Restrict drawing to a rectangle. Useful for UI panels, split-screen, transitions.\nAlways in SCREEN space — it does not follow camera_ex() zoom/rotation.\nclip(0, 0, 0, 0) disables clipping.\n✓ ENGINE-CLEARED: unlike camera/pal/fillp/fade (which you must reset), the engine turns clip off for you at the end of every frame — so a forgotten clip can never blank the next frame.', docNL: 'Beperk het tekenen tot een rechthoek. Handig voor UI-panelen, split-screen en overgangen.\nAltijd in SCHERM-coördinaten — het volgt geen zoom/rotatie van camera_ex().\nclip(0, 0, 0, 0) schakelt clipping uit.\n✓ DOOR DE ENGINE GEWIST: anders dan camera/pal/fillp/fade (die je zelf moet terugzetten) schakelt de engine clip aan het einde van elk frame voor je uit — een vergeten clip kan het volgende frame dus nooit zwart maken.' },
  mget:       { sig: 'int mget(int cx, int cy)',                                       doc: 'Read the tile index stored in map cell (cx, cy). Returns 0 if out of bounds.\nFor pixel-space collision use tile_at(px, py), which handles the cell size for you.', docNL: 'Lees de tile-index in mapcel (cx, cy). Geeft 0 buiten de map.\nVoor collision in pixels gebruik je tile_at(px, py), dat met de celgrootte rekening houdt.' },
  mset:       { sig: 'void mset(int cx, int cy, int sprite_index)',                    doc: 'Write a sprite index into map cell (cx, cy). Out-of-bounds writes are silently ignored.', docNL: 'Schrijf een sprite-index in mapcel (cx, cy). Schrijven buiten de map wordt stilletjes genegeerd.' },
  map:        { sig: 'void map(int cx, int cy, int sx, int sy, int cw, int ch)',       doc: 'Draw a cw×ch chunk of the map starting at cell (cx,cy) to screen position (sx,sy).\nEach cell is a CELL_W×CELL_H rect of the spritesheet (set in the map tab). Value-0 cells are skipped.\nRespects camera() and map_scale().', docNL: 'Teken een cw×ch deel van de map vanaf cel (cx,cy) naar schermpositie (sx,sy).\nElke cel is een CELL_W×CELL_H stuk van de spritesheet (instelbaar in de map-tab). Cellen met waarde 0 worden overgeslagen.\nHoudt rekening met camera() en map_scale().' },
  map_scale:  { sig: 'void map_scale(int n)',                                          doc: 'Integer zoom for map drawing. map_scale(1) draws cells at their native CELL_W×CELL_H (default);\nmap_scale(4) draws them 4× as big. tile_at() and touching_map() follow the same scale.', docNL: 'Hele-getal-zoom voor het tekenen van de map. map_scale(1) tekent cellen op hun eigen CELL_W×CELL_H (standaard);\nmap_scale(4) tekent ze 4× zo groot. tile_at() en touching_map() volgen dezelfde schaal.' },
  MAP_W:      { sig: '#define MAP_W 128',                                              doc: 'Map width in cells.', docNL: 'Breedte van de map in cellen.' },
  MAP_H:      { sig: '#define MAP_H 64',                                               doc: 'Map height in cells.', docNL: 'Hoogte van de map in cellen.' },
  print:          { sig: 'int print(const char *text, int x, int y, int color)',          doc: 'Draw text at (x, y) using the active font. Returns x after the last char — use it to chain segments or detect overflow.\nint x2 = print("score ", 4, 4, CLR_WHITE); print(str("%d", score), x2, 4, CLR_YELLOW);', docNL: 'Teken tekst op (x, y) met het actieve lettertype. Geeft x na het laatste teken terug — gebruik dit om segmenten te koppelen of overloop te detecteren.\nint x2 = print("score ", 4, 4, CLR_WHITE); print(str("%d", score), x2, 4, CLR_YELLOW);' },
  print_centered: { sig: 'int print_centered(const char *text, int y, int color)',        doc: 'Draw text centered horizontally on screen at height y. Returns x after the last char.', docNL: 'Teken tekst horizontaal gecentreerd op het scherm op hoogte y. Geeft x na het laatste teken terug.' },
  print_right:    { sig: 'int print_right(const char *text, int right_x, int y, int color)', doc: 'Draw text right-aligned so its last character ends at right_x. Returns x after the last char.', docNL: 'Teken tekst rechts uitgelijnd zodat het laatste teken eindigt bij right_x. Geeft x na het laatste teken terug.' },
  rect:       { sig: 'void rect(int x, int y, int w, int h, int color)',              doc: 'Draw a rectangle border.', docNL: 'Teken de rand van een rechthoek.' },
  rectfill:   { sig: 'void rectfill(int x, int y, int w, int h, int color)',          doc: 'Draw a filled rectangle.', docNL: 'Teken een gevulde rechthoek.' },
  bar:        { sig: 'void bar(int x, int y, int w, int h, float pct, int fill, int bg)', doc: 'Draw a progress/health bar: a bg-colored box with a left-to-right fill.\npct is 0..1 (clamped). bar(10, 8, 80, 5, hp / 100.0f, CLR_RED, CLR_DARK_RED);', docNL: 'Teken een voortgangs-/levensbalk: een vakje in de bg-kleur met een vulling van links naar rechts.\npct is 0..1 (begrensd). bar(10, 8, 80, 5, hp / 100.0f, CLR_RED, CLR_DARK_RED);' },
  circ:       { sig: 'void circ(int x, int y, int radius, int color)',                doc: 'Draw a circle border.', docNL: 'Teken de rand van een cirkel.' },
  circfill:   { sig: 'void circfill(int x, int y, int radius, int color)',            doc: 'Draw a filled circle.', docNL: 'Teken een gevulde cirkel.' },
  tri:        { sig: 'void tri(int x1, int y1, int x2, int y2, int x3, int y3, int color)',     doc: 'Draw a triangle border through three points.', docNL: 'Teken de rand van een driehoek door drie punten.' },
  trifill:    { sig: 'void trifill(int x1, int y1, int x2, int y2, int x3, int y3, int color)', doc: 'Draw a filled triangle. Vertex order does not matter.', docNL: 'Teken een gevulde driehoek. Volgorde van hoekpunten maakt niet uit.' },
  tritex:     { sig: 'void tritex(int x1, int y1, float u1, float v1, int x2, int y2, float u2, float v2, int x3, int y3, float u3, float v3)',
               doc: 'Texture-mapped triangle — the textured-3D primitive. Each corner maps a screen point (x,y) to a pixel on the sprite sheet (u,v, in sheet pixels, 0–127). The texture is interpolated across the triangle in screen space with no perspective correction — the authentic affine "swimmy" PS1 look. For 3D, project your model to 2D yourself, then feed the screen coords here. Sampling is nearest-neighbour; sheet transparency shows through.\ntritex(10,10,0,0, 90,20,16,0, 50,90,8,16);',
               docNL: 'Driehoek met textuur — de bouwsteen voor 3D met plaatjes. Elke hoek koppelt een schermpunt (x,y) aan een pixel op de sprite-sheet (u,v, in sheet-pixels, 0–127). De textuur wordt over de driehoek geïnterpoleerd in schermruimte zonder perspectiefcorrectie — de echte affiene, "zwemmende" PS1-look. Voor 3D projecteer je je model zelf naar 2D en geef je die schermcoördinaten hier door. Bemonstering is nearest-neighbour; doorzichtige sheet-pixels blijven doorzichtig.\ntritex(10,10,0,0, 90,20,16,0, 50,90,8,16);' },
  line:       { sig: 'void line(int x1, int y1, int x2, int y2, int color)',          doc: 'Draw a line from (x1, y1) to (x2, y2).', docNL: 'Teken een lijn van (x1, y1) naar (x2, y2).' },
  pset:       { sig: 'void pset(int x, int y, int color)',                            doc: 'Set a single pixel at (x, y). Pairs with pget().', docNL: 'Zet één pixel op (x, y). Hoort bij pget().' },
  BTN_UP:     { sig: '#define BTN_UP 0',                                              doc: 'Up button.', docNL: 'Knop omhoog.' },
  BTN_DOWN:   { sig: '#define BTN_DOWN 1',                                            doc: 'Down button.', docNL: 'Knop omlaag.' },
  BTN_LEFT:   { sig: '#define BTN_LEFT 2',                                            doc: 'Left button.', docNL: 'Knop naar links.' },
  BTN_RIGHT:  { sig: '#define BTN_RIGHT 3',                                           doc: 'Right button.', docNL: 'Knop naar rechts.' },
  BTN_A:      { sig: '#define BTN_A 4',                                               doc: 'A button. Player 0: Z  Player 1: ,', docNL: 'A-knop. Speler 0: Z  Speler 1: ,' },
  BTN_B:      { sig: '#define BTN_B 5',                                               doc: 'B button. Player 0: X  Player 1: .', docNL: 'B-knop. Speler 0: X  Speler 1: .' },
  SCREEN_W:   { sig: '#define SCREEN_W 320',                                          doc: 'Width of the screen in pixels. Configurable in settings.', docNL: 'Breedte van het scherm in pixels. Aan te passen in instellingen.' },
  SCREEN_H:   { sig: '#define SCREEN_H 200',                                          doc: 'Height of the screen in pixels. Configurable in settings.', docNL: 'Hoogte van het scherm in pixels. Aan te passen in instellingen.' },
  CLR_BLACK:          { sig: '#define CLR_BLACK 0',           doc: 'Palette index for black (#000000).',          docNL: 'Paletindex voor zwart (#000000).' },
  CLR_DARK_BLUE:      { sig: '#define CLR_DARK_BLUE 1',       doc: 'Palette index for dark blue (#1d2b53).',      docNL: 'Paletindex voor donkerblauw (#1d2b53).' },
  CLR_DARK_PURPLE:    { sig: '#define CLR_DARK_PURPLE 2',     doc: 'Palette index for dark purple (#7e2553).',    docNL: 'Paletindex voor donkerpaars (#7e2553).' },
  CLR_DARK_GREEN:     { sig: '#define CLR_DARK_GREEN 3',      doc: 'Palette index for dark green (#008751).',     docNL: 'Paletindex voor donkergroen (#008751).' },
  CLR_BROWN:          { sig: '#define CLR_BROWN 4',           doc: 'Palette index for brown (#ab5236).',          docNL: 'Paletindex voor bruin (#ab5236).' },
  CLR_DARK_GREY:      { sig: '#define CLR_DARK_GREY 5',       doc: 'Palette index for dark grey (#5f574f).',      docNL: 'Paletindex voor donkergrijs (#5f574f).' },
  CLR_LIGHT_GREY:     { sig: '#define CLR_LIGHT_GREY 6',      doc: 'Palette index for light grey (#c2c3c7).',     docNL: 'Paletindex voor lichtgrijs (#c2c3c7).' },
  CLR_WHITE:          { sig: '#define CLR_WHITE 7',           doc: 'Palette index for white (#fff1e8).',          docNL: 'Paletindex voor wit (#fff1e8).' },
  CLR_RED:            { sig: '#define CLR_RED 8',             doc: 'Palette index for red (#ff004d).',            docNL: 'Paletindex voor rood (#ff004d).' },
  CLR_ORANGE:         { sig: '#define CLR_ORANGE 9',          doc: 'Palette index for orange (#ffa300).',         docNL: 'Paletindex voor oranje (#ffa300).' },
  CLR_YELLOW:         { sig: '#define CLR_YELLOW 10',         doc: 'Palette index for yellow (#ffec27).',         docNL: 'Paletindex voor geel (#ffec27).' },
  CLR_GREEN:          { sig: '#define CLR_GREEN 11',          doc: 'Palette index for green (#00e436).',          docNL: 'Paletindex voor groen (#00e436).' },
  CLR_BLUE:           { sig: '#define CLR_BLUE 12',           doc: 'Palette index for blue (#29adff).',           docNL: 'Paletindex voor blauw (#29adff).' },
  CLR_INDIGO:         { sig: '#define CLR_INDIGO 13',         doc: 'Palette index for indigo (#83769c).',         docNL: 'Paletindex voor indigo (#83769c).' },
  CLR_PINK:           { sig: '#define CLR_PINK 14',           doc: 'Palette index for pink (#ff77a8).',           docNL: 'Paletindex voor roze (#ff77a8).' },
  CLR_LIGHT_PEACH:    { sig: '#define CLR_LIGHT_PEACH 15',    doc: 'Palette index for light peach (#ffccaa).',    docNL: 'Paletindex voor lichtperzik (#ffccaa).' },
  CLR_BROWNISH_BLACK: { sig: '#define CLR_BROWNISH_BLACK 16', doc: 'Palette index for brownish black (#291814).', docNL: 'Paletindex voor bruinzwart (#291814).' },
  CLR_DARKER_BLUE:    { sig: '#define CLR_DARKER_BLUE 17',    doc: 'Palette index for darker blue (#111d35).',    docNL: 'Paletindex voor donkerder blauw (#111d35).' },
  CLR_DARKER_PURPLE:  { sig: '#define CLR_DARKER_PURPLE 18',  doc: 'Palette index for darker purple (#422136).',  docNL: 'Paletindex voor donkerder paars (#422136).' },
  CLR_BLUE_GREEN:     { sig: '#define CLR_BLUE_GREEN 19',     doc: 'Palette index for blue green (#125359).',     docNL: 'Paletindex voor blauwgroen (#125359).' },
  CLR_DARK_BROWN:     { sig: '#define CLR_DARK_BROWN 20',     doc: 'Palette index for dark brown (#742f29).',     docNL: 'Paletindex voor donkerbruin (#742f29).' },
  CLR_DARKER_GREY:    { sig: '#define CLR_DARKER_GREY 21',    doc: 'Palette index for darker grey (#49333b).',    docNL: 'Paletindex voor donkerder grijs (#49333b).' },
  CLR_MEDIUM_GREY:    { sig: '#define CLR_MEDIUM_GREY 22',    doc: 'Palette index for medium grey (#a28879).',    docNL: 'Paletindex voor middengrijs (#a28879).' },
  CLR_LIGHT_YELLOW:   { sig: '#define CLR_LIGHT_YELLOW 23',   doc: 'Palette index for light yellow (#f3ef7d).',   docNL: 'Paletindex voor lichtgeel (#f3ef7d).' },
  CLR_DARK_RED:       { sig: '#define CLR_DARK_RED 24',       doc: 'Palette index for dark red (#be1250).',       docNL: 'Paletindex voor donkerrood (#be1250).' },
  CLR_DARK_ORANGE:    { sig: '#define CLR_DARK_ORANGE 25',    doc: 'Palette index for dark orange (#ff6c24).',    docNL: 'Paletindex voor donkeroranje (#ff6c24).' },
  CLR_LIME_GREEN:     { sig: '#define CLR_LIME_GREEN 26',     doc: 'Palette index for lime green (#a8e72e).',     docNL: 'Paletindex voor limoengroen (#a8e72e).' },
  CLR_MEDIUM_GREEN:   { sig: '#define CLR_MEDIUM_GREEN 27',   doc: 'Palette index for medium green (#00b543).',   docNL: 'Paletindex voor middengroen (#00b543).' },
  CLR_TRUE_BLUE:      { sig: '#define CLR_TRUE_BLUE 28',      doc: 'Palette index for true blue (#065ab5).',      docNL: 'Paletindex voor helderblauw (#065ab5).' },
  CLR_MAUVE:          { sig: '#define CLR_MAUVE 29',          doc: 'Palette index for mauve (#754665).',          docNL: 'Paletindex voor mauve (#754665).' },
  CLR_DARK_PEACH:     { sig: '#define CLR_DARK_PEACH 30',     doc: 'Palette index for dark peach (#ff6e59).',     docNL: 'Paletindex voor donkerperzik (#ff6e59).' },
  CLR_PEACH:          { sig: '#define CLR_PEACH 31',          doc: 'Palette index for peach (#ff9d81).',          docNL: 'Paletindex voor perzik (#ff9d81).' },
  sfx:          { sig: 'void sfx(int n)',                                             doc: 'Play sound effect slot n. -1 stops all sfx.\nDemo slots: 0 coin, 1 zap, 2 jump, 3 explosion.', docNL: 'Speel geluidseffect n af. -1 stopt alle effecten.\nDemo-slots: 0 munt, 1 zap, 2 sprong, 3 explosie.' },
  music:        { sig: 'void music(int n)',                                           doc: 'Play music pattern n. -1 stops music.\nDemo slot 0 is a bass+hihat loop.', docNL: 'Speel muziekpatroon n af. -1 stopt de muziek.\nDemo-slot 0 is een bas+hihat-loop.' },
  note:         { sig: 'void note(int midi, int instr, int vol)',                     doc: 'One-shot note (~250ms).\nmidi: MIDI note (60 = middle C). instr: INSTR_*.  vol: 0–7.', docNL: 'Eenmalige noot (~250ms).\nmidi: MIDI-noot (60 = centrale C). instr: INSTR_*.  vol: 0–7.' },
  hit:          { sig: 'void hit(int midi, int instr, int vol, int dur_ms)',          doc: 'Like note() but you choose how long it rings.\nClosed hihat: hit(72, INSTR_NOISE, 3, 30).\nOpen hihat: hit(72, INSTR_NOISE, 3, 200).\nStaccato vs sustained = same lever.', docNL: 'Net als note(), maar jij kiest hoe lang hij naklinkt.\nGesloten hihat: hit(72, INSTR_NOISE, 3, 30).\nOpen hihat: hit(72, INSTR_NOISE, 3, 200).\nKort (staccato) of lang aanhoudend — zelfde knop.' },
  instrument:   { sig: 'void instrument(int slot, int wave, int attack_ms, int decay_ms, int sustain, int release_ms)', doc: 'Define an instrument in `slot` (5–15): a waveform shaped by an ADSR envelope. Then play it like any wave with note(midi, slot, vol).\nattack/decay/release in ms, sustain 0–7. Slots 0–4 are the built-in waves.\nPluck: instrument(5, INSTR_SAW, 2, 90, 1, 120).\nPad:   instrument(6, INSTR_SINE, 300, 0, 7, 500).', docNL: 'Maak een instrument in `slot` (5–15): een golfvorm met een ADSR-envelope eromheen. Speel het daarna als elke golf met note(midi, slot, vol).\nattack/decay/release in ms, sustain 0–7. Slots 0–4 zijn de ingebouwde golven.\nPluk: instrument(5, INSTR_SAW, 2, 90, 1, 120).\nPad:  instrument(6, INSTR_SINE, 300, 0, 7, 500).' },
  instrument_duty: { sig: 'void instrument_duty(int slot, float duty)',                doc: 'Set the pulse width of a square-wave instrument slot. 0.5 = full square, 0.12 = thin/nasal, 0.25 = hollow. No effect on saw/tri/sine/noise.\ninstrument_duty(7, 0.12);', docNL: 'Stel de pulsbreedte in van een blokgolf-instrument. 0.5 = volle blokgolf, 0.12 = dun/nasaal, 0.25 = hol. Geen effect op zaag/driehoek/sinus/ruis.\ninstrument_duty(7, 0.12);' },
  instrument_lfo: { sig: 'void instrument_lfo(int slot, int which, int dest, float rate_hz, float depth)', doc: 'Attach a slow sine LFO to an instrument, wobbling a parameter over time. A slot has 3 LFOs — `which` is 0, 1, or 2 — so you can vibrato AND sweep a filter at once. dest picks what each moves:\nLFO_PITCH = vibrato (depth in semitones), LFO_DUTY = PWM shimmer (square only), LFO_VOLUME = tremolo, LFO_CUTOFF = filter sweep/wah (depth in Hz).\nrate is the wobble speed in Hz (4–8 is typical). depth 0 = off.\ninstrument_lfo(5, 0, LFO_PITCH, 6, 0.3);  // gentle vibrato on LFO 0', docNL: 'Hang een trage sinus-LFO aan een instrument die een parameter laat golven. Een slot heeft 3 LFO\'s — `which` is 0, 1 of 2 — dus je kunt tegelijk vibrato geven én een filter sweepen. dest kiest wat elk beweegt:\nLFO_PITCH = vibrato (diepte in halve tonen), LFO_DUTY = PWM-glinstering (alleen blokgolf), LFO_VOLUME = tremolo, LFO_CUTOFF = filter-sweep/wah (diepte in Hz).\nrate is de golfsnelheid in Hz (4–8 is normaal). depth 0 = uit.\ninstrument_lfo(5, 0, LFO_PITCH, 6, 0.3);  // zachte vibrato op LFO 0' },
  LFO_PITCH:    { sig: '#define LFO_PITCH 0',  doc: 'LFO target: pitch → vibrato. depth is in semitones (0.3 subtle, 2 wide).', docNL: 'LFO-doel: toonhoogte → vibrato. depth in halve tonen (0.3 subtiel, 2 breed).' },
  LFO_DUTY:     { sig: '#define LFO_DUTY 1',   doc: 'LFO target: pulse width → PWM shimmer. Square-wave slots only. depth 0.0..0.5.', docNL: 'LFO-doel: pulsbreedte → PWM-glinstering. Alleen blokgolf-slots. depth 0.0..0.5.' },
  LFO_VOLUME:   { sig: '#define LFO_VOLUME 2', doc: 'LFO target: volume → tremolo. depth 0.0..1.0 (how deep it dips).', docNL: 'LFO-doel: volume → tremolo. depth 0.0..1.0 (hoe diep het wegzakt).' },
  LFO_CUTOFF:   { sig: '#define LFO_CUTOFF 3', doc: 'LFO target: filter cutoff → sweep/wah. depth in Hz. Needs a filter on the slot.', docNL: 'LFO-doel: filter-cutoff → sweep/wah. depth in Hz. Vereist een filter op het slot.' },
  instrument_filter: { sig: 'void instrument_filter(int slot, int mode, int cutoff_hz, int resonance)', doc: 'Run an instrument through a resonant filter — the tone-sculpting knob.\nmode: FILTER_LOW (warm), FILTER_HIGH (thin), FILTER_BAND (vowel), FILTER_NOTCH (phasey).\ncutoff in Hz (try 400–2000). resonance 0–15 — high adds a whistly peak at the cutoff.\nSweep the cutoff for a wah with instrument_lfo(slot, LFO_CUTOFF, 0.5, 800).\ninstrument_filter(5, FILTER_LOW, 800, 10);', docNL: 'Stuur een instrument door een resonant filter — de knop om de klankkleur te boetseren.\nmode: FILTER_LOW (warm), FILTER_HIGH (dun), FILTER_BAND (klinker), FILTER_NOTCH (faserig).\ncutoff in Hz (probeer 400–2000). resonance 0–15 — hoog geeft een fluitende piek bij de cutoff.\nVeeg de cutoff voor een wah met instrument_lfo(slot, LFO_CUTOFF, 0.5, 800).\ninstrument_filter(5, FILTER_LOW, 800, 10);' },
  FILTER_OFF:   { sig: '#define FILTER_OFF 0',   doc: 'No filter (default).', docNL: 'Geen filter (standaard).' },
  FILTER_LOW:   { sig: '#define FILTER_LOW 1',   doc: 'Lowpass — keeps lows, muffles highs. Warm/round.', docNL: 'Laagdoorlaat — houdt lage tonen, dempt hoge. Warm/rond.' },
  FILTER_HIGH:  { sig: '#define FILTER_HIGH 2',  doc: 'Highpass — keeps highs, thins out lows. Tinny/bright.', docNL: 'Hoogdoorlaat — houdt hoge tonen, dunt lage uit. Blikkerig/helder.' },
  FILTER_BAND:  { sig: '#define FILTER_BAND 3',  doc: 'Bandpass — keeps only a band around the cutoff. Vowel/wah.', docNL: 'Banddoorlaat — houdt alleen een band rond de cutoff. Klinker/wah.' },
  FILTER_NOTCH: { sig: '#define FILTER_NOTCH 4', doc: 'Notch — scoops OUT a band around the cutoff. Phasey/hollow.', docNL: 'Notch — schept een band rond de cutoff WEG. Faserig/hol.' },
  INSTR_SQUARE: { sig: '#define INSTR_SQUARE 0',                                      doc: 'Square wave — chiptune lead.', docNL: 'Blokgolf — chiptune-lead.' },
  INSTR_SAW:    { sig: '#define INSTR_SAW 1',                                         doc: 'Sawtooth — bright, buzzy.', docNL: 'Zaagtand — helder, zoemend.' },
  INSTR_TRI:    { sig: '#define INSTR_TRI 2',                                         doc: 'Triangle — soft, flute-like.', docNL: 'Driehoek — zacht, fluitachtig.' },
  INSTR_NOISE:  { sig: '#define INSTR_NOISE 3',                                       doc: 'Noise — hihats, explosions.', docNL: 'Ruis — hihats, explosies.' },
  INSTR_SINE:   { sig: '#define INSTR_SINE 4',                                        doc: 'Sine — pure tone.', docNL: 'Sinus — zuivere toon.' },
  tone:           { sig: 'void tone(int scale, int octave, int instr, int vol)',       doc: 'Play a random note from a musical scale.\noctave 3–6 typical (4 = middle C).', docNL: 'Speel een willekeurige noot uit een toonladder.\noctaaf 3–6 gebruikelijk (4 = centrale C).' },
  SCALE_MAJOR:    { sig: '#define SCALE_MAJOR 0',                                      doc: 'Major scale — happy, do re mi.', docNL: 'Majeur-toonladder — vrolijk, do re mi.' },
  SCALE_MINOR:    { sig: '#define SCALE_MINOR 1',                                      doc: 'Natural minor — sad / mysterious.', docNL: 'Natuurlijk mineur — droevig / mysterieus.' },
  SCALE_PENTA:    { sig: '#define SCALE_PENTA 2',                                      doc: 'Major pentatonic (5 notes) — always sounds nice, hard to play a wrong note.', docNL: 'Majeur-pentatonisch (5 noten) — klinkt altijd goed, moeilijk om een foute noot te spelen.' },
  SCALE_PENTA_MIN:{ sig: '#define SCALE_PENTA_MIN 3',                                  doc: 'Minor pentatonic — bluesy, moody.', docNL: 'Mineur-pentatonisch — bluesy, sfeervol.' },
  SCALE_BLUES:    { sig: '#define SCALE_BLUES 4',                                      doc: 'Blues scale — minor penta + flat 5.', docNL: 'Blues-toonladder — mineur-penta + verlaagde kwint.' },
  SCALE_CHROMATIC:{ sig: '#define SCALE_CHROMATIC 5',                                  doc: 'All 12 semitones — atonal, dissonant.', docNL: 'Alle 12 halve tonen — atonaal, dissonant.' },
  chord:          { sig: 'void chord(int root, int type, int instr, int vol)',         doc: 'Play a chord stacked on a MIDI root note.\nroot: MIDI note (60 = middle C). type: CHORD_*.', docNL: 'Speel een akkoord, opgebouwd op een MIDI-grondtoon.\nroot: MIDI-noot (60 = centrale C). type: CHORD_*.' },
  strum:          { sig: 'void strum(int root, int type, int instr, int vol, int delay_ms)', doc: 'Like chord(), but notes are spread across delay_ms apart (~20–80ms feels guitar-like).\nNegative delay_ms strums from high to low (down-strum).', docNL: 'Net als chord(), maar de noten worden delay_ms uit elkaar gespreid (~20–80ms voelt gitaarachtig).\nNegatieve delay_ms tokkelt van hoog naar laag (neerwaartse slag).' },
  schedule:       { sig: 'void schedule(int delay_ms, int midi, int instr, int vol)',  doc: 'Play a note delay_ms in the future. Non-blocking — queues into the audio thread.', docNL: 'Speel een noot delay_ms in de toekomst. Blokkeert niet — wordt in de audio-thread gezet.' },
  bpm:            { sig: 'void bpm(int rate)',                                         doc: 'Set tempo in beats per minute (default 120).', docNL: 'Stel het tempo in beats per minuut in (standaard 120).' },
  beat:           { sig: 'int beat()',                                                 doc: 'Current beat counter — advances each beat based on bpm().', docNL: 'Huidige beat-teller — gaat elke beat één omhoog, op basis van bpm().' },
  every:          { sig: 'bool every(int n)',                                          doc: 'True once per n beats, on the beat. Use in update() to fire something rhythmically:\nif (every(4)) chord(60, CHORD_MAJ7, INSTR_TRI, 5);', docNL: 'Geeft true één keer per n beats, precies op de beat. Gebruik in update() om iets ritmisch te laten gebeuren:\nif (every(4)) chord(60, CHORD_MAJ7, INSTR_TRI, 5);' },
  beat_pos:       { sig: 'float beat_pos()',                                           doc: 'Fractional position within the current beat: 0.0 just after a beat hits, approaching 1.0 just before the next one. Useful for fades, pulses, and continuous modulation.', docNL: 'Waar je zit binnen de huidige beat: 0.0 net na een beat, oplopend naar 1.0 vlak voor de volgende. Handig voor fades, pulsen en doorlopende modulatie.' },
  euclid:         { sig: 'bool euclid(int hits, int steps, int b)',                    doc: 'Bjorklund/Euclidean rhythm — true when step b is one of `hits` spread as evenly as possible across `steps`. Not just for music: it distributes ANY repeating event evenly. Pass any counter as b — beat(), frame()/10, a wave index — to spawn enemies, place pickups, or stagger blinks on a regular-but-not-boring cadence.\neuclid(3, 8, beat()) → tresillo beat  •  euclid(2, 7, frame()/30) → an event on 2 of every 7 ticks.', docNL: 'Björklund/Euclidisch ritme — geeft true als stap b één van de `hits` is, zo gelijkmatig mogelijk verdeeld over `steps`. Niet alleen voor muziek: het verdeelt élke herhalende gebeurtenis gelijkmatig. Geef een willekeurige teller mee als b — beat(), frame()/10, een golf-index — om vijanden te spawnen, pickups te plaatsen of knipperingen te spreiden.\neuclid(3, 8, beat()) → tresillo  •  euclid(2, 7, frame()/30) → gebeurtenis op 2 van elke 7 ticks.' },
  chance:         { sig: 'bool chance(int percent)',                                   doc: 'True with the given probability percent (0–100) — a weighted coin flip. Used all over, not just music: random item drops, enemy variety, branching events, occasional glitches, "did it hit?" rolls.\nif (chance(30)) drop_powerup();   •   if (every(1) && chance(40)) note(60, INSTR_SAW, 4);', docNL: 'Geeft true met de opgegeven kans in procenten (0–100) — een gewogen muntworp. Overal bruikbaar, niet alleen muziek: willekeurige item-drops, variatie in vijanden, vertakkende gebeurtenissen, af en toe een glitch, "raak het?"-worpen.\nif (chance(30)) drop_powerup();   •   if (every(1) && chance(40)) note(60, INSTR_SAW, 4);' },
  degree:         { sig: 'int degree(int scale, int octave, int n)',                   doc: 'MIDI note for the nth degree of a scale, rooted at C. Wraps octaves for n outside the scale length, so degree(SCALE_PENTA, 4, 7) is one octave up from degree 2.', docNL: 'MIDI-noot voor de n-de trap van een toonladder, met C als grondtoon. Loopt door naar volgende octaven als n buiten de lengte van de ladder valt, dus degree(SCALE_PENTA, 4, 7) ligt een octaaf hoger dan trap 2.' },
  CHORD_MAJ:      { sig: '#define CHORD_MAJ 0',                                        doc: 'Major triad — bright, resolved.', docNL: 'Majeur-drieklank — helder, opgelost.' },
  CHORD_MIN:      { sig: '#define CHORD_MIN 1',                                        doc: 'Minor triad — sad, soft.', docNL: 'Mineur-drieklank — droevig, zacht.' },
  CHORD_DIM:      { sig: '#define CHORD_DIM 2',                                        doc: 'Diminished — tense, unresolved.', docNL: 'Verminderde drieklank — gespannen, onopgelost.' },
  CHORD_AUG:      { sig: '#define CHORD_AUG 3',                                        doc: 'Augmented — uneasy, dreamlike.', docNL: 'Overmatige drieklank — onrustig, dromerig.' },
  CHORD_MAJ7:     { sig: '#define CHORD_MAJ7 4',                                       doc: 'Major 7th — jazzy, sophisticated.', docNL: 'Majeur-septiem — jazzy, verfijnd.' },
  CHORD_MIN7:     { sig: '#define CHORD_MIN7 5',                                       doc: 'Minor 7th — smooth, soulful.', docNL: 'Mineur-septiem — soepel, soulvol.' },
  CHORD_DOM7:     { sig: '#define CHORD_DOM7 6',                                       doc: 'Dominant 7th — bluesy, wants to resolve.', docNL: 'Dominant-septiem — bluesy, wil oplossen.' },
  CHORD_SUS4:     { sig: '#define CHORD_SUS4 7',                                       doc: 'Suspended 4th — open, suspended.', docNL: 'Sus4 (voorhouding) — open, zwevend.' },
  CHORD_POWER:    { sig: '#define CHORD_POWER 8',                                      doc: 'Power chord — root + fifth, no third. Rock staple.', docNL: 'Powerchord — grondtoon + kwint, geen terts. Rock-klassieker.' },
  rnd:                { sig: 'int rnd(int n)',                                              doc: 'Random integer in [0, n). rnd(6) returns 0–5.', docNL: 'Willekeurig heel getal in [0, n). rnd(6) geeft 0–5.' },
  rnd_between:        { sig: 'int rnd_between(int lo, int hi)',                           doc: 'Random integer in [lo, hi). rnd_between(3, 8) returns 3–7.', docNL: 'Willekeurig heel getal in [lo, hi). rnd_between(3, 8) geeft 3–7.' },
  rnd_float:          { sig: 'float rnd_float()',                                         doc: 'Random float 0..1.', docNL: 'Willekeurig kommagetal 0..1.' },
  rnd_float_between:  { sig: 'float rnd_float_between(float lo, float hi)',               doc: 'Random float in [lo, hi).', docNL: 'Willekeurig kommagetal in [lo, hi).' },
  now:                { sig: 'float now()',                                                doc: 'Seconds since startup. Use for animations and oscillators.', docNL: 'Seconden sinds het opstarten. Gebruik voor animaties en oscillatoren.' },
  epoch:              { sig: 'int epoch()',                                                doc: 'Real-world clock: Unix time in whole seconds. Unlike now(), it keeps counting while the cart is closed.\nSave it with save(), then on the next run compare to tell how long the player was away:\nint away = epoch() - load(0);  // seconds since last visit', docNL: 'Echte klok: Unix-tijd in hele seconden. Anders dan now() telt deze door terwijl de cart dicht is.\nSla hem op met save() en vergelijk bij de volgende run hoe lang de speler weg was:\nint away = epoch() - load(0);  // seconden sinds het laatste bezoek' },
  frame:              { sig: 'int frame()',                                                doc: 'Frame count since startup. Increments once per update().\nif (frame() % 30 == 0) fires twice per second at 60fps.', docNL: 'Aantal frames sinds het opstarten. Verhoogt eenmaal per update().\nif (frame() % 30 == 0) vuurt twee keer per seconde bij 60fps.' },
  fps:                { sig: 'int fps()',                                                  doc: 'Measured frames per second right now, smoothed over the last second. 60 means the cart is running smoothly; a lower number means it is too slow. Show it while tuning performance:\nwatch("fps", "%d", fps());', docNL: 'Gemeten frames per seconde op dit moment, gemiddeld over de laatste seconde. 60 betekent dat de cart soepel draait; een lager getal betekent te traag. Toon het tijdens het optimaliseren:\nwatch("fps", "%d", fps());' },
  sgn:            { sig: 'int sgn(int n)',                                             doc: 'Sign of n: -1 if negative, 0 if zero, 1 if positive.', docNL: 'Het teken van n (positief/negatief): -1 als negatief, 0 bij nul, 1 als positief.' },
  mid:            { sig: 'int mid(int a, int b, int c)',                               doc: 'Middle value of three. Common use is clamp: mid(lo, value, hi).', docNL: 'Middelste waarde van drie. Vaak gebruikt om te begrenzen: mid(lo, waarde, hi).' },

  printh:         { sig: 'void printh(const char *fmt, ...)',                          doc: 'printf-style logging to the editor\'s runtime log panel (not the game window).\nAnswers "what is this value?" and "did this run?".\nExample: printh("score %d", score);', docNL: 'printf-achtig loggen naar het runtime-logpaneel van de editor (niet het spelvenster).\nBeantwoordt "wat is deze waarde?" en "is dit uitgevoerd?".\nVoorbeeld: printh("score %d", score);' },
  watch:          { sig: 'void watch(const char *name, const char *fmt, ...)',         doc: 'Show a named, live value in the corner of the game window. printf-style, so it works for any type.\nExample: watch("x", "%d", x);  watch("pos", "(%d, %d)", x, y);\nA value fades out about a second after you stop calling watch() for it. Press F1 to hide/show.', docNL: 'Toon een benoemde, live waarde in de hoek van het spelvenster. printf-achtig, dus werkt voor elk type.\nVoorbeeld: watch("x", "%d", x);  watch("pos", "(%d, %d)", x, y);\nEen waarde verdwijnt ongeveer een seconde nadat je watch() er niet meer voor aanroept. Druk op F1 om te tonen/verbergen.' },
  watch_visible:  { sig: 'void watch_visible(bool on)',                                doc: 'Show or hide the watch() overlay (default: on). Handy for clean screenshots. F1 toggles it too.', docNL: 'Toon of verberg de watch()-overlay (standaard: aan). Handig voor nette screenshots. F1 schakelt het ook.' },

  timer:          { sig: 'float timer()',                                              doc: 'Seconds since the last timer_reset() (or startup). A resettable stopwatch.\nUse for round timers, "how long did you survive?", cooldowns.', docNL: 'Seconden sinds de laatste timer_reset() (of het opstarten). Een resetbare stopwatch.\nVoor rondetijden, "hoe lang overleefde je?", cooldowns.' },
  timer_reset:    { sig: 'void timer_reset()',                                          doc: 'Reset timer() back to 0.', docNL: 'Zet timer() terug op 0.' },
  save:       { sig: 'void save(int slot, int value)', doc: 'Store an integer that survives between runs. 64 slots (0–63) per cart, written to cart.sav.\nTypical use: save(0, high_score);', docNL: 'Sla een heel getal op dat bewaard blijft tussen sessies. 64 slots (0–63) per cart, opgeslagen in cart.sav.\nTypisch gebruik: save(0, high_score);' },
  load:       { sig: 'int load(int slot)',              doc: 'Read back a saved value. Returns 0 if the slot was never written.\nTypical use: int hi = load(0);', docNL: 'Lees een opgeslagen waarde terug. Geeft 0 als het slot nooit beschreven is.\nTypisch gebruik: int hi = load(0);' },
  save_int:   { sig: 'void save_int(const char *key, int value)', doc: 'Store an integer by name instead of a slot number — no numbering to remember. Up to 64 keys per cart.\nsave_int("hiscore", score);', docNL: 'Sla een heel getal op onder een naam in plaats van een slotnummer — geen nummering om te onthouden. Tot 64 namen per cart.\nsave_int("hiscore", score);' },
  load_int:   { sig: 'int load_int(const char *key, int def)', doc: 'Read a named value back. Returns `def` if that key was never saved.\nint hi = load_int("hiscore", 0);', docNL: 'Lees een waarde terug op naam. Geeft `def` terug als die naam nooit is opgeslagen.\nint hi = load_int("hiscore", 0);' },

  // ── math ── (angles in degrees: 0 = right, 90 = down)
  abs:        { sig: 'int abs(int v)',                                                 doc: 'Absolute value — drops the minus sign. abs(-5) is 5.', docNL: 'Absolute waarde — haalt het minteken weg. abs(-5) is 5.' },
  min:        { sig: 'int min(int a, int b)',                                          doc: 'The smaller of two numbers.', docNL: 'De kleinste van twee getallen.' },
  max:        { sig: 'int max(int a, int b)',                                          doc: 'The bigger of two numbers.', docNL: 'De grootste van twee getallen.' },
  clamp:      { sig: 'float clamp(float v, float lo, float hi)',                       doc: 'Keep v between lo and hi. Below lo gives lo, above hi gives hi.\nFloat-friendly version of mid(lo, v, hi).', docNL: 'Houd v tussen lo en hi. Onder lo wordt het lo, boven hi wordt het hi.\nFloat-vriendelijke versie van mid(lo, v, hi).' },
  blink:          { sig: 'bool blink(int period)',         doc: 'Flashing helper driven by frame(): true for `period` frames, then false for `period` frames, repeating.\nblink(3) is a fast flash; blink(15) a slow one. Use it to flash an invincible player:\nif (invincible && blink(3)) spr(0, x, y);  // skip the draw on the off frames', docNL: 'Knipperhulp op basis van frame(): waar gedurende `period` frames, dan onwaar gedurende `period` frames, herhaald.\nblink(3) knippert snel; blink(15) langzaam. Gebruik het om een onkwetsbare speler te laten knipperen:\nif (invincible && blink(3)) spr(0, x, y);' },
  ease_in:        { sig: 'float ease_in(float t)',       doc: 'Start slow, end fast. t must be 0..1. Compose with lerp:\nfloat x = lerp(startX, endX, ease_in(t));', docNL: 'Begin langzaam, eindig snel. t moet 0..1 zijn.' },
  ease_out:       { sig: 'float ease_out(float t)',      doc: 'Start fast, end slow. t must be 0..1.', docNL: 'Begin snel, eindig langzaam. t moet 0..1 zijn.' },
  ease_in_out:    { sig: 'float ease_in_out(float t)',   doc: 'Slow → fast → slow. The most natural-feeling easing. t must be 0..1.', docNL: 'Langzaam → snel → langzaam. De meest natuurlijke easing. t moet 0..1 zijn.' },
  lerp:       { sig: 'float lerp(float a, float b, float t)',                          doc: 'Mix between a and b. t=0 gives a, t=1 gives b, t=0.5 the middle.\nGreat for smooth camera follow, fades, color blends.', docNL: 'Meng tussen a en b. t=0 geeft a, t=1 geeft b, t=0.5 het midden.\nFijn voor een soepele camera, fades en kleurovergangen.' },
  remap:      { sig: 'float remap(float v, float a, float b, float c, float d)',       doc: 'Remap v from the range a..b into the range c..d.\nremap(health, 0, 100, 0, SCREEN_W) turns health into a bar width.', docNL: 'Zet v om van bereik a..b naar bereik c..d.\nremap(health, 0, 100, 0, SCREEN_W) maakt van health een balkbreedte.' },
  distance:   { sig: 'float distance(int x1, int y1, int x2, int y2)',                 doc: 'Distance between two points, in pixels.', docNL: 'Afstand tussen twee punten, in pixels.' },
  length:     { sig: 'float length(int x, int y)',                                     doc: 'Length of the vector (x, y) — its distance from the origin.', docNL: 'Lengte van de vector (x, y) — de afstand tot de oorsprong.' },
  fsqrt:      { sig: 'float fsqrt(float v)',                                           doc: 'Square root of v. Returns 0 for v <= 0, so it never errors.\nHandy for vector magnitudes without including math.h: float d = fsqrt(dx*dx + dy*dy);', docNL: 'Vierkantswortel van v. Geeft 0 voor v <= 0, dus het geeft nooit een fout.\nHandig voor de lengte van een vector zonder math.h: float d = fsqrt(dx*dx + dy*dy);' },
  angle_to:   { sig: 'float angle_to(int x1, int y1, int x2, int y2)',                 doc: 'Direction in degrees from point 1 to point 2.\n0 = right, 90 = down, 180 = left, -90 = up. Pairs with dx()/dy().', docNL: 'Richting in graden van punt 1 naar punt 2.\n0 = rechts, 90 = omlaag, 180 = links, -90 = omhoog. Hoort bij dx()/dy().' },
  dx:         { sig: 'float dx(float steps, float degrees)',                           doc: 'How far to move in x when stepping `steps` pixels at this angle.\nKeep position in a float so sub-pixel motion adds up: x += dx(2, dir);', docNL: 'Hoeveel je in x beweegt als je `steps` pixels in deze hoek stapt.\nBewaar de positie in een float zodat subpixel-beweging optelt: x += dx(2, dir);' },
  dy:         { sig: 'float dy(float steps, float degrees)',                           doc: 'How far to move in y when stepping `steps` pixels at this angle.\nPairs with dx() — y grows downward. Keep position in a float.', docNL: 'Hoeveel je in y beweegt als je `steps` pixels in deze hoek stapt.\nHoort bij dx() — y groeit naar beneden. Bewaar de positie in een float.' },
  sin_deg:    { sig: 'float sin_deg(float degrees)',                                   doc: 'Sine of an angle in degrees (-1.0 to 1.0).', docNL: 'Sinus van een hoek in graden (-1.0 tot 1.0).' },
  cos_deg:    { sig: 'float cos_deg(float degrees)',                                   doc: 'Cosine of an angle in degrees (-1.0 to 1.0).', docNL: 'Cosinus van een hoek in graden (-1.0 tot 1.0).' },

  // ── collision ──
  boxes_touch:     { sig: 'bool boxes_touch(int ax, int ay, int aw, int ah, int bx, int by, int bw, int bh)', doc: 'True if two rectangles overlap. The everyday sprite collision check (AABB).', docNL: 'True als twee rechthoeken overlappen. De alledaagse sprite-collision (AABB).' },
  point_in_box:    { sig: 'bool point_in_box(int px, int py, int bx, int by, int bw, int bh)', doc: 'True if the point (px, py) is inside the rectangle.', docNL: 'True als het punt (px, py) binnen de rechthoek ligt.' },
  circles_touch:   { sig: 'bool circles_touch(int ax, int ay, int ar, int bx, int by, int br)', doc: 'True if two circles overlap (centres + radii).', docNL: 'True als twee cirkels overlappen (middelpunten + stralen).' },
  near:            { sig: 'bool near(int ax, int ay, int bx, int by, int d)',          doc: 'True if the two points are within d pixels of each other.', docNL: 'True als de twee punten binnen d pixels van elkaar liggen.' },
  touching_map:    { sig: 'bool touching_map(int x, int y, int w, int h)',             doc: 'True if this pixel-space box overlaps any non-empty map cell (value != 0).\nThe easy "am I standing on a wall?" check.', docNL: 'True als deze box (in pixels) een niet-lege mapcel raakt (waarde != 0).\nDe makkelijke "sta ik op een muur?"-check.' },
  tile_at:         { sig: 'int tile_at(int px, int py)',                               doc: 'Tile index of the map cell under pixel (px, py). 0 if empty/out of bounds.\nConverts pixels → cell using the current cell size and map_scale().', docNL: 'Tile-index van de mapcel onder pixel (px, py). 0 als leeg/buiten beeld.\nRekent pixels → cel om met de huidige celgrootte en map_scale().' },
  touching_color:  { sig: 'bool touching_color(int x, int y, int w, int h, int color)', doc: 'True if any pixel inside this box is the given palette color.\nPaint your walls one color, then ask "am I touching it?" — collision with no hitboxes.', docNL: 'True als een pixel in deze box de opgegeven paletkleur heeft.\nGeef je muren één kleur en vraag "raak ik die?" — collision zonder hitboxes.' },
  bounce_at_edges: { sig: 'void bounce_at_edges(int *x, int *y, int *vx, int *vy, int w, int h)', doc: 'Flip the velocity when a w×h box hits a screen edge — the classic DVD-logo bounce.\nPass addresses: bounce_at_edges(&x, &y, &vx, &vy, 16, 16);', docNL: 'Draait de snelheid om als een w×h box de schermrand raakt — de klassieke DVD-logo bounce.\nGeef adressen mee: bounce_at_edges(&x, &y, &vx, &vy, 16, 16);' },

  // ── animation ──
  anim:       { sig: 'int anim(int n_frames, float fps, float phase)',                 doc: 'Which animation frame to show right now (0..n_frames-1), looping forever.\nphase 0..1 offsets the cycle start — use (float)i/count to stagger multiple entities.\nspr(walk + anim(4, 10, 0), x, y); — a 4-frame walk cycle at 10 fps.\nspr(walk + anim(4, 10, (float)i/5), x, y); — 5 entities walking out of phase.', docNL: 'Welk animatieframe nu te tonen (0..n_frames-1), eindeloos herhalend.\nphase 0..1 verschuift de cyclusstart — gebruik (float)i/aantal om meerdere figuren te verspringen.\nspr(walk + anim(4, 10, 0), x, y); — een loopcyclus van 4 frames op 10 fps.' },
  anim_once:  { sig: 'int anim_once(int n_frames, float fps, float start_t)',          doc: 'Like anim(), but plays once from start_t and stays on the last frame.\nUse now() as start_t when the action begins (e.g. an explosion).', docNL: 'Net als anim(), maar speelt één keer vanaf start_t en blijft op het laatste frame staan.\nGebruik now() als start_t wanneer de actie begint (bijv. een explosie).' },

  // ── strings ──
  str:        { sig: 'const char *str(const char *fmt, ...)',                          doc: 'Build a string with values in it, printf-style, for print().\nprint(str("score %d", score), 4, 4, CLR_WHITE);\nReuses a few buffers — fine within a frame, don\'t store the result.', docNL: 'Bouw een tekst met waarden erin, printf-stijl, voor print().\nprint(str("score %d", score), 4, 4, CLR_WHITE);\nHergebruikt een paar buffers — prima binnen een frame, bewaar het resultaat niet.' },
  noise:      { sig: 'float noise(float x)',                   doc: 'Smooth random value 0..1. Nearby x values give similar results — great for wobble, pulses, organic motion.\nnoise(now()) drifts slowly over time.', docNL: 'Soepele willekeurige waarde 0..1. Nabijgelegen x-waarden geven vergelijkbare resultaten — fijn voor wiebelende beweging, golven en organisch gedrag.\nnoise(now()) drijft langzaam mee met de tijd.' },
  noise2:     { sig: 'float noise2(float x, float y)',         doc: 'Smooth 2D random value 0..1. Use for terrain height, fog density, flow fields.\nScale your inputs: noise2(x*0.05, y*0.05) for gentle hills.', docNL: 'Soepele 2D-willekeurige waarde 0..1. Handig voor terreinhoogte, mistdichtheid en stroom­velden.\nSchaal je invoer: noise2(x*0.05, y*0.05) voor zachte heuvels.' },
  noise3:     { sig: 'float noise3(float x, float y, float z)', doc: 'Smooth 3D random value 0..1. Animates 2D noise by passing now() as z.\nnoise3(x*0.05, y*0.05, now()*0.5) gives slowly drifting terrain.', docNL: 'Soepele 3D-willekeurige waarde 0..1. Animeer 2D-ruis door now() als z door te geven.\nnoise3(x*0.05, y*0.05, now()*0.5) geeft langzaam drijvend terrein.' },

  // ── 3D helpers ──
  V3:         { sig: 'typedef struct { float x, y, z; } V3', doc: 'A 3D point/vector — three floats. Build a model from a list of these, then rot3/project them.\nV3 p = { 1, -1, 2 };', docNL: 'Een 3D-punt/vector — drie floats. Bouw een model uit een lijst hiervan en gebruik dan rot3/project.\nV3 p = { 1, -1, 2 };' },
  rot3:       { sig: 'V3 rot3(V3 p, float yaw, float pitch)', doc: 'Rotate a point: yaw (around the Y axis) then pitch (around the X axis), both in degrees. The everyday spin-a-model call.\nV3 r = rot3(vert[i], angle, 20);', docNL: 'Roteer een punt: yaw (om de Y-as) en daarna pitch (om de X-as), beide in graden. De alledaagse "draai een model"-aanroep.\nV3 r = rot3(vert[i], hoek, 20);' },
  project3:   { sig: 'bool project3(V3 p, float focal, float zoom, int *sx, int *sy)', doc: 'Perspective-divide a rotated point to screen pixels (origin = screen centre). Bigger focal = flatter; zoom scales it up. Returns false if the point is behind the camera.\nint x, y; if (project3(r, 4, 48, &x, &y)) circfill(x, y, 2, 7);', docNL: 'Perspectief-deel een geroteerd punt naar schermpixels (oorsprong = schermmidden). Grotere focal = platter; zoom schaalt op. Geeft false als het punt achter de camera ligt.\nint x, y; if (project3(r, 4, 48, &x, &y)) circfill(x, y, 2, 7);' },
  zsort:      { sig: 'void zsort(float *key, int *order, int n)', doc: 'Painter\'s sort: fills order[] with indices 0..n-1 ordered far→near by key[]. No z-buffer needed — draw your faces/sprites via order[i].\nfloat z[N]; int o[N]; zsort(z, o, n); for (i) draw(face[o[i]]);', docNL: 'Schildersortering: vult order[] met indices 0..n-1, ver→dichtbij gesorteerd op key[]. Geen z-buffer nodig — teken je vlakken/sprites via order[i].\nfloat z[N]; int o[N]; zsort(z, o, n); for (i) draw(face[o[i]]);' },
  quadfill:   { sig: 'void quadfill(int x0, int y0, int x1, int y1, int x2, int y2, int x3, int y3, int color)', doc: 'Fill a four-cornered polygon (two triangles sharing the 0–2 diagonal). Corners go in order around the face. The solid-3D / road-segment workhorse.\nquadfill(x0,y0, x1,y1, x2,y2, x3,y3, CLR_BLUE);', docNL: 'Vul een vierhoek (twee driehoeken die de 0–2-diagonaal delen). Hoeken gaan op volgorde rond het vlak. De werkpaard voor solide 3D / wegsegmenten.\nquadfill(x0,y0, x1,y1, x2,y2, x3,y3, CLR_BLUE);' },
  ngon:       { sig: 'void ngon(int x, int y, int r, int sides, float rot, int color)',         doc: 'Regular n-sided polygon outline. rot=0 puts the first point to the right (degrees). ngon(x,y,r,6,0,c) = hexagon, ngon(...,3,...) = triangle.\nngon(80, 60, 20, 6, 0, CLR_WHITE);', docNL: 'Omtrek van een regelmatige n-hoek. rot=0 zet het eerste punt naar rechts (graden).\nngon(80, 60, 20, 6, 0, CLR_WHITE);' },
  ngonfill:   { sig: 'void ngonfill(int x, int y, int r, int sides, float rot, int color)',     doc: 'Filled regular polygon — triangle fan from the center. Respects fillp(). ngonfill(x,y,r,6,0,c) = solid hexagon.\nngonfill(80, 60, 20, 6, 30, CLR_GREEN);', docNL: 'Gevulde regelmatige n-hoek — driehoekswaaier vanuit het middelpunt. Respecteert fillp().\nngonfill(80, 60, 20, 6, 30, CLR_GREEN);' },
  star:       { sig: 'void star(int x, int y, int r_out, int r_in, int points, float rot, int color)',     doc: 'Star outline. r_out = tip radius, r_in = inner radius, points = number of tips. rot in degrees.\nstar(80, 60, 20, 8, 5, 0, CLR_YELLOW);', docNL: 'Ster-omtrek. r_out = puntstraal, r_in = binnenstraal, points = aantal punten. rot in graden.\nstar(80, 60, 20, 8, 5, 0, CLR_YELLOW);' },
  starfill:   { sig: 'void starfill(int x, int y, int r_out, int r_in, int points, float rot, int color)', doc: 'Filled star. Respects fillp(). Great for sparkles, badges, pickups.\nstarfill(80, 60, 20, 8, 5, 0, CLR_YELLOW);', docNL: 'Gevulde ster. Respecteert fillp(). Mooi voor vonkjes, badges en power-ups.\nstarfill(80, 60, 20, 8, 5, 0, CLR_YELLOW);' },
  poly:       { sig: 'void poly(int *xy, int n, int color)',     doc: 'Polygon outline through n points, auto-closed. xy is a flat array of pairs: {x0,y0, x1,y1, ...}.\nint pts[] = {10,10, 50,5, 60,40, 20,45}; poly(pts, 4, CLR_WHITE);', docNL: 'Veelhoek-omtrek door n punten, automatisch gesloten. xy is een platte array van paren: {x0,y0, x1,y1, ...}.\nint pts[] = {10,10, 50,5, 60,40, 20,45}; poly(pts, 4, CLR_WHITE);' },
  polyfill:   { sig: 'void polyfill(int *xy, int n, int color)', doc: 'Filled polygon through n points (even-odd coverage — handles concave shapes too). Respects fillp().\nint pts[] = {10,10, 50,5, 60,40, 20,45}; polyfill(pts, 4, CLR_BLUE);', docNL: 'Gevulde veelhoek door n punten (even-oneven dekking — werkt ook voor concave vormen). Respecteert fillp().\nint pts[] = {10,10, 50,5, 60,40, 20,45}; polyfill(pts, 4, CLR_BLUE);' },
  thickline:  { sig: 'void thickline(int x1, int y1, int x2, int y2, int w, int color)', doc: 'Line with pixel width w. Round caps at both ends. w=1 behaves like line().\nthickline(10, 10, 90, 50, 4, CLR_RED);', docNL: 'Lijn met pixelbreedte w. Ronde kapjes aan beide uiteinden. w=1 gedraagt zich als line().\nthickline(10, 10, 90, 50, 4, CLR_RED);' },
  thicklineoutline: { sig: 'void thicklineoutline(int x1, int y1, int x2, int y2, int w, int color)', doc: 'Outline of a thick line — the capsule (stadium) border. Hugs thickline() exactly; draw over a thickline fill for a bordered cable.\nthicklineoutline(10, 10, 90, 50, 8, CLR_WHITE);', docNL: 'Omtrek van een dikke lijn — de capsule- (stadion-)rand. Sluit precies om thickline(); teken over een thickline-vulling voor een omrande kabel.\nthicklineoutline(10, 10, 90, 50, 8, CLR_WHITE);' },
  rrect:      { sig: 'void rrect(int x, int y, int w, int h, int r, int color)',      doc: 'Rounded rectangle outline. r = corner radius in pixels.\nrrect(10, 10, 80, 40, 6, CLR_WHITE);', docNL: 'Afgeronde rechthoek-omtrek. r = hoekstraal in pixels.\nrrect(10, 10, 80, 40, 6, CLR_WHITE);' },
  rrectfill:  { sig: 'void rrectfill(int x, int y, int w, int h, int r, int color)', doc: 'Filled rounded rectangle. Panels, buttons, speech bubbles.\nrrectfill(10, 10, 80, 40, 6, CLR_DARK_BLUE);', docNL: 'Gevulde afgeronde rechthoek. Panelen, knoppen, tekstballonnen.\nrrectfill(10, 10, 80, 40, 6, CLR_DARK_BLUE);' },
  vgradient:  { sig: 'void vgradient(int x, int y, int w, int h, int c_top, int c_bot)',    doc: 'Vertical dithered gradient from c_top to c_bot. Replaces stacks of rectfill for skies and backdrops.\nvgradient(0, 0, SCREEN_W, SCREEN_H, CLR_DARK_BLUE, CLR_BLACK);', docNL: 'Verticaal geditherd kleurverloop van c_top naar c_bot. Vervangt stapels rectfill voor luchten en achtergronden.\nvgradient(0, 0, SCREEN_W, SCREEN_H, CLR_DARK_BLUE, CLR_BLACK);' },
  hgradient:  { sig: 'void hgradient(int x, int y, int w, int h, int c_left, int c_right)', doc: 'Horizontal dithered gradient from c_left to c_right. Side lighting, panels.\nhgradient(0, 0, SCREEN_W, 20, CLR_DARK_GREY, CLR_BLACK);', docNL: 'Horizontaal geditherd kleurverloop van c_left naar c_right. Zijverlichting, panelen.\nhgradient(0, 0, SCREEN_W, 20, CLR_DARK_GREY, CLR_BLACK);' },

  // ── c basics ── (kind: 'keyword' = skipped by autocomplete, but still used for hover tooltips and the help tab)
  include:    { kind: 'keyword', sig: '#include "studio.h"',                            doc: 'Pulls in declarations from another file. #include "studio.h" gives you every dreamengine function and constant.',                          docNL: 'Haalt declaraties uit een ander bestand binnen. #include "studio.h" geeft je toegang tot alle dreamengine-functies en constanten.' },
  define:     { kind: 'keyword', sig: '#define NAME 42',                                doc: 'Gives a value a name. Used for constants like screen size or button IDs. No semicolon at the end.',                                       docNL: 'Geeft een waarde een naam. Wordt gebruikt voor constanten zoals schermgrootte of knop-ID\'s. Geen puntkomma aan het eind.' },
  int:        { kind: 'keyword', sig: 'int x = 5;',                                     doc: 'A whole number, no decimals. Can be negative. Math like + - * / % all work on it.',                                                          docNL: 'Een heel getal, zonder decimalen. Mag negatief zijn. Rekenen met + - * / % werkt allemaal.' },
  float:      { kind: 'keyword', sig: 'float p = 0.5f;',                                doc: 'A number with decimals. Use the f suffix on literals: 1.5f, not 1.5.',                                                                     docNL: 'Een getal met decimalen. Gebruik de f-suffix bij waarden: 1.5f, geen 1.5.' },
  bool:       { kind: 'keyword', sig: 'bool ok = true;',                                doc: 'True or false, nothing else. Used for flags and conditions.',                                                                              docNL: 'True of false, meer niet. Voor schakelaars en voorwaarden.' },
  void:       { kind: 'keyword', sig: 'void update() { ... }',                          doc: '"Nothing." A function declared void runs but doesn\'t hand back a value.',                                                                 docNL: '"Niets". Een functie met void doet wel iets, maar geeft geen waarde terug.' },
  if:         { kind: 'keyword', sig: 'if (x > 10) { ... } else { ... }',               doc: 'Run the block only when the condition is true. Pair with else for the "otherwise" branch.',                                              docNL: 'Voert het blok alleen uit als de voorwaarde waar is. Combineer met else voor "anders".' },
  for:        { kind: 'keyword', sig: 'for (int i = 0; i < 10; i++) { ... }',           doc: 'Counted loop. Three parts inside the parens: starting value, condition to keep going, step at the end of each pass.',                       docNL: 'Tellende lus. Drie delen tussen de haakjes: startwaarde, voorwaarde om door te gaan, stap aan het einde van elke ronde.' },
  return:     { kind: 'keyword', sig: 'return 42;',                                     doc: 'Leave the current function. If the function has a return type, the value follows.',                                                        docNL: 'Verlaat de huidige functie. Als de functie een retourtype heeft, geef je de waarde mee.' },
  logical:    { kind: 'keyword', sig: 'if (a && !b) { ... }',                           doc: 'Logical operators: && (and) needs both true; || (or) needs at least one; ! flips true and false.',                                       docNL: 'Logische operatoren: && (en) eist allebei waar; || (of) eist minstens één; ! draait true en false om.' },
  equality:   { kind: 'keyword', sig: 'if (x == 5)   vs   x = 5;',                      doc: 'One = assigns: x = 5 puts 5 into x. Two == compares: x == 5 asks "is x equal to 5?". Mistaking the two is one of the most common bugs in C.', docNL: 'Eén = is toekennen: x = 5 zet 5 in x. Twee == is vergelijken: x == 5 vraagt "is x gelijk aan 5?". Deze door elkaar halen is één van de meest voorkomende fouten in C.' },
  comment:    { kind: 'keyword', sig: '// this is ignored',                             doc: 'A comment. Everything from // to the end of the line is for humans only — the compiler skips it.',                                         docNL: 'Een comment. Alles vanaf // tot het einde van de regel is alleen voor mensen — de compiler slaat het over.' },
  braces:     { kind: 'keyword', sig: '{ ... }',                                        doc: 'Curly braces group statements into a block. Functions, if, for, while all use them.',                                                      docNL: 'Accolades groeperen statements in een blok. Functies, if, for, while gebruiken ze allemaal.' },
  semicolon:  { kind: 'keyword', sig: 'x = 5;',                                         doc: 'Every statement ends with one. If your code doesn\'t compile, a missing ; is suspect #1.',                                                 docNL: 'Elke statement eindigt met een puntkomma. Compileert je code niet? Een vergeten ; is de #1 verdachte.' },
  array:      { kind: 'keyword', sig: 'int a[] = { 1, 2, 3 };',                         doc: 'A fixed-length list of values of the same type. Access elements with a[0], a[1], a[2]. The size is set when you create it.',             docNL: 'Een lijst met een vaste lengte, allemaal van hetzelfde type. Benader elementen met a[0], a[1], a[2]. De lengte staat vast vanaf het moment dat je hem aanmaakt.' },
  static:     { kind: 'keyword', sig: 'static int counter = 0;',                        doc: 'Two uses. Inside a function: the variable keeps its value across calls — perfect for a frame counter that survives between update()s without being a global. At file scope: makes a variable or function private to this file.', docNL: 'Twee betekenissen. Binnen een functie: de variabele behoudt zijn waarde tussen aanroepen — handig voor bijvoorbeeld een frame-teller die tussen update()-aanroepen overleeft, zonder dat het een globale variabele wordt. Buiten elke functie: maakt de variabele of functie privé voor dit bestand.' },
}
